package org.apache.flink.streaming.api.windowing.assigners;

import org.apache.flink.annotation.PublicEvolving;
import org.apache.flink.api.common.ExecutionConfig;
import org.apache.flink.api.common.typeutils.TypeSerializer;
import org.apache.flink.streaming.api.windowing.triggers.EventTimeTrigger;
import org.apache.flink.streaming.api.windowing.triggers.Trigger;
import org.apache.flink.streaming.api.windowing.windows.TimeWindow;

import java.time.LocalTime;
import java.time.ZoneId;
import java.time.ZonedDateTime;
import java.util.Collection;
import java.util.Collections;

/**
 * A {@link MergingWindowAssigner} that windows elements into sessions based on market trading
 * hours. Windows represent complete trading sessions (e.g., NYSE 09:30-16:00 ET) and can handle
 * multiple markets with different trading hours and timezones.
 *
 * <p>Elements are assigned to the trading session that contains their timestamp. Sessions may span
 * multiple calendar days (e.g., overnight futures markets) and do not overlap.
 *
 * <p>Example usage for NYSE trading hours (09:30-16:00 ET):
 *
 * <pre>{@code
 * DataStream<PriceEvent> stream = ...;
 * KeyedStream<PriceEvent, String> keyed = stream.keyBy(e -> e.getSymbol());
 * WindowedStream<PriceEvent, String, TimeWindow> windowed =
 *   keyed.window(PricingSessionWindow.forMarket("NYSE",
 *     ZoneId.of("America/New_York"),
 *     LocalTime.of(9, 30),
 *     LocalTime.of(16, 0)));
 * }</pre>
 */
@PublicEvolving
public class PricingSessionWindow extends MergingWindowAssigner<Object, TimeWindow> {
    private static final long serialVersionUID = 1L;

    private final String marketId;
    private final ZoneId timezone;
    private final LocalTime sessionOpen;
    private final LocalTime sessionClose;

    /**
     * Creates a new PricingSessionWindow for a single market.
     *
     * @param marketId Identifier for the market (e.g., "NYSE", "LSE")
     * @param timezone The timezone of the market (e.g., ZoneId.of("America/New_York"))
     * @param sessionOpen The local time when the market opens (e.g., LocalTime.of(9, 30))
     * @param sessionClose The local time when the market closes (e.g., LocalTime.of(16, 0))
     */
    private PricingSessionWindow(
            String marketId, ZoneId timezone, LocalTime sessionOpen, LocalTime sessionClose) {
        if (marketId == null || marketId.isEmpty()) {
            throw new IllegalArgumentException("Market ID cannot be null or empty");
        }
        if (timezone == null) {
            throw new IllegalArgumentException("Timezone cannot be null");
        }
        if (sessionOpen == null || sessionClose == null) {
            throw new IllegalArgumentException("Session open and close times cannot be null");
        }
        if (!sessionOpen.isBefore(sessionClose)) {
            throw new IllegalArgumentException(
                    "Session open time must be before close time (for same-day sessions)");
        }

        this.marketId = marketId;
        this.timezone = timezone;
        this.sessionOpen = sessionOpen;
        this.sessionClose = sessionClose;
    }

    /**
     * Factory method to create a PricingSessionWindow for a specific market.
     *
     * @param marketId Identifier for the market (e.g., "NYSE", "LSE")
     * @param timezone The timezone of the market
     * @param sessionOpen The local time when the market opens
     * @param sessionClose The local time when the market closes
     * @return A new PricingSessionWindow instance
     */
    public static PricingSessionWindow forMarket(
            String marketId, ZoneId timezone, LocalTime sessionOpen, LocalTime sessionClose) {
        return new PricingSessionWindow(marketId, timezone, sessionOpen, sessionClose);
    }

    @Override
    public Collection<TimeWindow> assignWindows(
            Object element, long timestamp, WindowAssignerContext context) {
        // Convert the timestamp (milliseconds since epoch) to a ZonedDateTime in the market's
        // timezone
        ZonedDateTime elementTime = ZonedDateTime.ofInstant(
                java.time.Instant.ofEpochMilli(timestamp), timezone);

        // Determine the session start and end times for the element's date
        ZonedDateTime sessionStart =
                elementTime.toLocalDate().atTime(sessionOpen).atZone(timezone);
        ZonedDateTime sessionEnd = elementTime.toLocalDate().atTime(sessionClose).atZone(timezone);

        // If the element's time is before the session open, it belongs to the previous day's
        // session
        // (for overnight sessions like futures)
        if (elementTime.isBefore(sessionStart)) {
            sessionStart = sessionStart.minusDays(1);
            sessionEnd = sessionEnd.minusDays(1);
        }

        // Convert back to epoch milliseconds
        long windowStart = sessionStart.toInstant().toEpochMilli();
        long windowEnd = sessionEnd.toInstant().toEpochMilli();

        return Collections.singletonList(new TimeWindow(windowStart, windowEnd));
    }

    @Override
    public Trigger<Object, TimeWindow> getDefaultTrigger() {
        return EventTimeTrigger.create();
    }

    @Override
    public TypeSerializer<TimeWindow> getWindowSerializer(ExecutionConfig executionConfig) {
        return new TimeWindow.Serializer();
    }

    @Override
    public boolean isEventTime() {
        return true;
    }

    @Override
    public void mergeWindows(
            Collection<TimeWindow> windows, MergingWindowAssigner.MergeCallback<TimeWindow> c) {
        TimeWindow.mergeWindows(windows, c);
    }

    @Override
    public String toString() {
        return String.format(
                "PricingSessionWindow(market=%s, tz=%s, open=%s, close=%s)",
                marketId, timezone, sessionOpen, sessionClose);
    }

    /**
     * Returns the market identifier.
     *
     * @return The market ID
     */
    public String getMarketId() {
        return marketId;
    }

    /**
     * Returns the market timezone.
     *
     * @return The timezone
     */
    public ZoneId getTimezone() {
        return timezone;
    }

    /**
     * Returns the session open time.
     *
     * @return The session open time
     */
    public LocalTime getSessionOpen() {
        return sessionOpen;
    }

    /**
     * Returns the session close time.
     *
     * @return The session close time
     */
    public LocalTime getSessionClose() {
        return sessionClose;
    }
}

