package org.apache.flink.streaming.api.windowing.triggers;

import org.apache.flink.annotation.PublicEvolving;
import org.apache.flink.streaming.api.windowing.windows.TimeWindow;

/**
 * A {@link Trigger} that fires when the market closes (at the end of the trading session window).
 * It registers an event-time timer for the window end and fires when the watermark passes that
 * time.
 *
 * <p>This trigger is designed to work with {@link
 * org.apache.flink.streaming.api.windowing.assigners.PricingSessionWindow} and supports window
 * merging for overlapping trading sessions.
 *
 * <p>Early firing on special events (e.g., circuit breaker halts) can be implemented by
 * subclassing or extending this trigger.
 */
@PublicEvolving
public class PricingSessionTrigger extends Trigger<Object, TimeWindow> {
    private static final long serialVersionUID = 1L;

    private PricingSessionTrigger() {}

    @Override
    public TriggerResult onElement(
            Object element, long timestamp, TimeWindow window, TriggerContext ctx)
            throws Exception {
        // Register a timer for the end of the session window
        long windowEnd = window.getEnd();
        if (windowEnd <= ctx.getCurrentWatermark()) {
            // If the watermark is already past the window end, fire immediately
            return TriggerResult.FIRE;
        } else {
            // Register a timer to fire at the window end
            ctx.registerEventTimeTimer(windowEnd);
            return TriggerResult.CONTINUE;
        }
    }

    @Override
    public TriggerResult onEventTime(long time, TimeWindow window, TriggerContext ctx) {
        // Fire when the event-time reaches the window end
        return time == window.getEnd() ? TriggerResult.FIRE : TriggerResult.CONTINUE;
    }

    @Override
    public TriggerResult onProcessingTime(long time, TimeWindow window, TriggerContext ctx) {
        // This trigger only uses event time
        return TriggerResult.CONTINUE;
    }

    @Override
    public void clear(TimeWindow window, TriggerContext ctx) throws Exception {
        // Delete the event-time timer registered for the window end
        ctx.deleteEventTimeTimer(window.getEnd());
    }

    @Override
    public boolean canMerge() {
        // This trigger supports window merging
        return true;
    }

    @Override
    public void onMerge(TimeWindow window, OnMergeContext ctx) throws Exception {
        // When windows are merged, re-register the timer for the merged window's end time
        long windowEnd = window.getEnd();
        if (windowEnd > ctx.getCurrentWatermark()) {
            ctx.registerEventTimeTimer(windowEnd);
        }
    }

    @Override
    public String toString() {
        return "PricingSessionTrigger()";
    }

    /**
     * Creates a new PricingSessionTrigger that fires at the end of a trading session window.
     *
     * @return A new PricingSessionTrigger instance
     */
    public static PricingSessionTrigger create() {
        return new PricingSessionTrigger();
    }
}

